const fire = $('Get Fire Details').first().json;
const waterPoints = $('Nearest Water Points').all().map(w => w.json);
const farm = $('Get Farm Access').first()?.json;
const groups = $('Get Responder Groups').all().map(g => g.json);

let waterInfo = waterPoints.map((wp, i) => `${i+1}. ${wp.name} (${wp.type}) - ${wp.status} - ${Math.round(wp.distance_m)}m away`).join('\n');

let farmInfo = '';
if (farm && farm.name) {
  farmInfo = `\n\nFARM: ${farm.name}\nOwner: ${farm.owner_name} (${farm.owner_phone || 'no phone'})\nGate code: ${farm.access_code || 'N/A'}\nNotes: ${farm.access_notes || 'None'}`;
  if (farm.gate_lat) farmInfo += `\nGate: ${farm.gate_lat}, ${farm.gate_lng}`;
}

const results = groups.map(g => ({
  phone: g.leader_phone,
  leader_name: g.leader_name,
  group_name: g.group_name,
  group_id: g.group_id,
  message: `FIRE ALERT\n${fire.fire_type} fire reported\nWind: ${fire.wind_direction || 'unknown'}\nLocation: ${fire.description}\n\nNearest water:\n${waterInfo}${farmInfo}\n\nRespond to confirm arrival.`
}));

return results.map(r => ({ json: r }));
